import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class MythicalBlueprintResultParser implements IMessageParser
{
private _success = false;
private _message = '';
private _appliedUpgradeId = 0;

public flush(): boolean
{
this._success = false;
this._message = '';
this._appliedUpgradeId = 0;
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
if(!wrapper) return false;

// Must match MythicalBlueprintResultComposer.java EXACTLY
this._success = wrapper.readBoolean();
this._message = wrapper.readString();
this._appliedUpgradeId = wrapper.readInt();

return true;
}

public get success(): boolean { return this._success; }
public get message(): string { return this._message; }
public get appliedUpgradeId(): number { return this._appliedUpgradeId; }
}

